const items = $input.all();
const apod = items[0]?.json || {};
const neoFeed = items[1]?.json || {};
const flareRaw = items[2]?.json || {};
const flareList = Array.isArray(flareRaw) ? flareRaw : (Array.isArray(flareRaw.data) ? flareRaw.data : []);

const today = new Date().toISOString().split('T')[0];

const neoData = neoFeed.near_earth_objects || {};
const asteroidsByDate = Object.entries(neoData).map(([date, asteroids]) => ({
  date,
  count: asteroids.length,
  hazardous: asteroids.filter(a => a.is_potentially_hazardous_asteroid).length
}));

const flareClassCounts = {};
flareList.forEach(f => {
  const cls = (f.classType || 'Unknown').charAt(0);
  flareClassCounts[cls] = (flareClassCounts[cls] || 0) + 1;
});

const totalAsteroids = asteroidsByDate.reduce((s, d) => s + d.count, 0);
const hazardous = asteroidsByDate.reduce((s, d) => s + d.hazardous, 0);
const flareCount = flareList.length;

const neoDates = JSON.stringify(asteroidsByDate.map(d => d.date));
const neoCounts = JSON.stringify(asteroidsByDate.map(d => d.count));
const neoHazard = JSON.stringify(asteroidsByDate.map(d => d.hazardous));
const flarePie = JSON.stringify(
  Object.entries(flareClassCounts).map(([k, v]) => ({ name: k + '급', value: v }))
);

const esc = (s) => String(s ?? '').replace(/[&<>"']/g, c => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c]));

const html = `<!DOCTYPE html>
<html lang="ko">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>NASA 우주 날씨 대시보드 - ${today}</title>
<script src="https://cdn.jsdelivr.net/npm/echarts@5.5.0/dist/echarts.min.js"></script>
<style>
  *{box-sizing:border-box}
  body{background:#0b0e14;color:#e6e6e6;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;margin:0;padding:24px;line-height:1.5}
  h1{color:#7dd3fc;margin:0 0 4px}
  h2{color:#a5b4fc;margin-top:0;font-size:1.1rem}
  h3{margin:8px 0;color:#fafafa}
  .meta{color:#94a3b8;margin-bottom:24px;font-size:.9rem}
  .grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(360px,1fr));gap:16px}
  .card{background:#161b22;border:1px solid #21262d;border-radius:12px;padding:20px}
  .full{grid-column:1/-1}
  .chart{width:100%;height:320px}
  img{max-width:100%;border-radius:8px;display:block;margin:8px 0}
  .stat{display:inline-block;margin-right:24px}
  .stat .num{font-size:1.6rem;font-weight:bold;color:#38bdf8}
  .stat .lbl{font-size:.85rem;color:#94a3b8;margin-left:4px}
</style>
</head>
<body>
<h1>🚀 NASA 우주 날씨 주간 대시보드</h1>
<div class="meta">업데이트: ${today} · Asia/Seoul</div>
<div class="card full" style="margin-bottom:16px">
  <span class="stat"><span class="num">${totalAsteroids}</span><span class="lbl">근접 소행성</span></span>
  <span class="stat"><span class="num">${hazardous}</span><span class="lbl">잠재 위험</span></span>
  <span class="stat"><span class="num">${flareCount}</span><span class="lbl">7일 플레어</span></span>
</div>
<div class="grid">
  <div class="card full">
    <h2>오늘의 천문사진 (APOD)</h2>
    <h3>${esc(apod.title)}</h3>
    ${apod.media_type === 'image' && apod.url ? `<img src="${esc(apod.url)}" alt="${esc(apod.title)}">` : ''}
    <p>${esc((apod.explanation || '').slice(0, 600))}${(apod.explanation || '').length > 600 ? '…' : ''}</p>
  </div>
  <div class="card">
    <h2>지구 근접 소행성 (오늘)</h2>
    <div id="neo" class="chart"></div>
  </div>
  <div class="card">
    <h2>태양 플레어 클래스 분포 (지난 7일)</h2>
    <div id="flare" class="chart"></div>
  </div>
</div>
<script>
const common = { backgroundColor:'transparent', textStyle:{color:'#e6e6e6'} };
const neoChart = echarts.init(document.getElementById('neo'),'dark');
neoChart.setOption({
  ...common,
  tooltip:{trigger:'axis'},
  legend:{textStyle:{color:'#e6e6e6'}},
  grid:{left:40,right:20,top:40,bottom:30},
  xAxis:{type:'category',data:${neoDates},axisLabel:{color:'#94a3b8'}},
  yAxis:{type:'value',axisLabel:{color:'#94a3b8'}},
  series:[
    {name:'전체',type:'bar',data:${neoCounts},itemStyle:{color:'#38bdf8'}},
    {name:'잠재 위험',type:'bar',data:${neoHazard},itemStyle:{color:'#f43f5e'}}
  ]
});
const flareChart = echarts.init(document.getElementById('flare'),'dark');
flareChart.setOption({
  ...common,
  tooltip:{trigger:'item'},
  legend:{bottom:0,textStyle:{color:'#e6e6e6'}},
  series:[{
    name:'클래스',type:'pie',radius:['40%','65%'],
    data:${flarePie},
    label:{color:'#e6e6e6'},
    itemStyle:{borderColor:'#0b0e14',borderWidth:2}
  }]
});
window.addEventListener('resize',()=>{neoChart.resize();flareChart.resize();});
</script>
</body>
</html>`;

const base64 = Buffer.from(html, 'utf-8').toString('base64');

const summary = `🪐 APOD: ${apod.title || '(없음)'}\n☄️ 오늘 근접 소행성 ${totalAsteroids}개 (잠재 위험 ${hazardous}개)\n☀️ 지난 7일 태양 플레어 ${flareCount}건`;

return [{
  json: {
    today,
    apodTitle: apod.title || '',
    apodUrl: apod.url || '',
    totalAsteroids,
    hazardous,
    flareCount,
    summary
  },
  binary: {
    data: {
      data: base64,
      mimeType: 'text/html',
      fileName: 'index.html'
    }
  }
}];
